#include <stdio.h>
#include <stdlib.h>

int countOddCoefficients(int m, int* exponents) {
    int count = 0;
    for (int i = 0; i <= 260; i++) {
        int coefficient = 0;
        for (int j = 0; j < m; j++) {
            for (int k = 0; k <= exponents[j]; k++) {
                if ((k & i) == k) {
                    coefficient++;
                }
            }
        }
        if (__builtin_popcount(coefficient) == 1) {
            count++;
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int m;
        scanf("%d", &m);
        int* exponents = (int*) malloc(m * sizeof(int));
        for (int i = 0; i < m; i++) {
            scanf("%d", &exponents[i]);
        }
        printf("%d\n", countOddCoefficients(m, exponents));
        free(exponents);
    }
    return 0;
}

