import java.util.Scanner;

public class Main {
    public static int countOddCoefficients(int m, int[] exponents) {
        int count = 0;
        for (int i = 0; i <= 260; i++) {
            int coefficient = 0;
            for (int j = 0; j < m; j++) {
                for (int k = 0; k <= exponents[j]; k++) {
                    if ((k & i) == k) {
                        coefficient++;
                    }
                }
            }
            if (Integer.bitCount(coefficient) == 1) {
                count++;
            }
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int m = scanner.nextInt();
            int[] exponents = new int[m];
            for (int i = 0; i < m; i++) {
                exponents[i] = scanner.nextInt();
            }
            System.out.println(countOddCoefficients(m, exponents));
        }
    }
}

